const now = new Date();
const today = now.toISOString().slice(0, 10);
const due = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
const runId = `N8N-STOCK-EXCHANGE-${Date.now()}`;
return [{ json: { runId, company: 'Thái Duy Digital', parentWarehouse: 'All Warehouses - TDD', postingDate: today, dueDate: due, customerName: `${runId} KH đổi sản phẩm`, itemGroup: `${runId} Nhóm đổi hàng`, sellWarehouseName: `${runId} Kho bán đổi`, returnWarehouseName: `${runId} Kho nhập trả đổi`, productA: `${runId} Sản phẩm A khách trả`, productB: `${runId} Sản phẩm B đổi mới`, feeItem: `${runId} Phí đổi trả`, receiptQtyA: 3, receiptQtyB: 3, saleQtyA: 1, returnQtyA: 1, exchangeQtyB: 1, rateA: 120, rateB: 150, feeRate: 15, accounts: { receivable: '1310 - Debtors - TDD', sales: '4110 - Sales - TDD' } } }];

const ctx = $('Build Exchange Fee Context').first().json;
const sellWh = $('Create Exchange Sell Warehouse').first().json.name;
const returnWh = $('Create Exchange Return Warehouse').first().json.name;
const binsA = $('Verify Product A Bins').all().map(i => i.json);
const binsB = $('Verify Product B Bins').all().map(i => i.json);
const sleA = $('Verify Product A SLE').all().map(i => i.json);
const sleB = $('Verify Product B SLE').all().map(i => i.json);
const byWhA = Object.fromEntries(binsA.map(row => [row.warehouse, Number(row.actual_qty)]));
const byWhB = Object.fromEntries(binsB.map(row => [row.warehouse, Number(row.actual_qty)]));
const saleA = $('Submit Original Sale A').first().json;
const creditA = $('Submit Return A Credit Note').first().json;
const fee = $('Submit Return Fee Invoice').first().json;
const saleB = $('Submit Exchange Sale B').first().json;
const saleARows = sleA.filter(row => row.voucher_no === saleA.name);
const returnRows = sleA.filter(row => row.voucher_no === creditA.name);
const saleBRows = sleB.filter(row => row.voucher_no === saleB.name);
const status = Number(saleA.docstatus) === 1 && Number(creditA.docstatus) === 1 && Number(fee.docstatus) === 1 && Number(saleB.docstatus) === 1 && byWhA[sellWh] === ctx.receiptQtyA - ctx.saleQtyA && byWhA[returnWh] === ctx.returnQtyA && byWhB[sellWh] === ctx.receiptQtyB - ctx.exchangeQtyB && saleARows.some(row => Number(row.actual_qty) === -ctx.saleQtyA) && returnRows.some(row => Number(row.actual_qty) === ctx.returnQtyA) && saleBRows.some(row => Number(row.actual_qty) === -ctx.exchangeQtyB);
const text = JSON.stringify({ binsA, binsB, sleA, sleB, fee: { name: fee.name, update_stock: fee.update_stock, grand_total: fee.grand_total } });
const securityFindings = ['api key', 'api_secret', 'authorization', 'token ', 'password'].filter(term => text.toLowerCase().includes(term));
return [{ json: { status: status && securityFindings.length === 0 ? 'passed' : 'failed', runId: ctx.runId, customer: $('Create Exchange Customer').first().json.name, productA: $('Create Product A').first().json.name, productB: $('Create Product B').first().json.name, feeItem: $('Create Exchange Fee Item').first().json.name, originalSaleInvoice: saleA.name, originalSaleDocstatus: saleA.docstatus, returnCreditNote: creditA.name, returnCreditNoteDocstatus: creditA.docstatus, returnAgainst: creditA.return_against, feeInvoice: fee.name, feeInvoiceDocstatus: fee.docstatus, feeGrandTotal: fee.grand_total, exchangeSaleInvoice: saleB.name, exchangeSaleDocstatus: saleB.docstatus, sellWarehouse: sellWh, returnWarehouse: returnWh, productASellQtyFinal: byWhA[sellWh], productAReturnQtyFinal: byWhA[returnWh], productBSellQtyFinal: byWhB[sellWh], productALedgerRows: sleA.length, productBLedgerRows: sleB.length, productASaleLedgerActualQty: saleARows.map(row => row.actual_qty), productAReturnLedgerActualQty: returnRows.map(row => row.actual_qty), productBExchangeLedgerActualQty: saleBRows.map(row => row.actual_qty), securityFindings } }];
